import java.util.*;
public class UnmodMap {
    public static void main(String[] args) {
        Map<String,Integer> m = new HashMap<>();
        m.put("x", 1);
        Map<String,Integer> unmod = Collections.unmodifiableMap(m);
        m.put("y", 2);   // modifying the backing map
        System.out.println(unmod.size());
        System.out.println(unmod.get("y"));
    }
}
